package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private static Method isLineBreakMethod;

    @BeforeAll
    public static void setUp() throws NoSuchMethodException {
        isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);
    }

    private boolean invokeIsLineBreak(char c) {
        try {
            // Pass Character object instead of primitive char
            return (boolean) isLineBreakMethod.invoke(null, Character.valueOf(c));
        } catch (IllegalAccessException | InvocationTargetException e) {
            throw new RuntimeException(e);
        }
    }

    @Test
    public void testIsLineBreak_withLF() {
        assertTrue(invokeIsLineBreak('\n')); // LF
    }

    @Test
    public void testIsLineBreak_withCR() {
        assertTrue(invokeIsLineBreak('\r')); // CR
    }

    @Test
    public void testIsLineBreak_withOtherChars() {
        assertFalse(invokeIsLineBreak('a'));
        assertFalse(invokeIsLineBreak(' '));
        assertFalse(invokeIsLineBreak('\t'));
        assertFalse(invokeIsLineBreak(','));
        assertFalse(invokeIsLineBreak('"'));
        assertFalse(invokeIsLineBreak('|'));
        assertFalse(invokeIsLineBreak('\\'));
        assertFalse(invokeIsLineBreak('#'));
        assertFalse(invokeIsLineBreak('\0'));
        assertFalse(invokeIsLineBreak('1'));
    }
}
